var e=[{id:`L2_1`,type:`dialog`,speaker:`FELICETTE_SPACESUIT_NULL_NULL`,text:{KOREA:`복수뿐이던 제 삶에 소중한 인연을 가져다준 건 코치에요.`,JPN:`復讐しかなかった私の人生に、大切な絆を与えてくれたのはコーチです。`,ENG:`It was you, Coach, who gave me something worth living for besides revenge.`,TWN:`是教練你將寶貴的關係帶進我原本只剩復仇的人生當中。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`FELICETTE_SPACESUIT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`FELICETTE_SPACESUIT_NULL_NULL`,text:{KOREA:`비록 전 아직 약하고 모르는 것도 많지만, 코치와 함께라면 분명 값진 승리를 쟁취할 수 있을 거예요. 이번에도 함께 해주실 거죠?`,JPN:`今の私はまだ弱いし、未熟だけど……コーチと一緒なら、きっと勝利を掴み取れると思います。今回も付いていてくれますよね？`,ENG:`I'm still weak and have so much to learn, but with you, I know I can claim a victory that's truly mine. You'll stay with me for that, right?`,TWN:`雖然我還很弱小，還有很多不成熟的地方，但只要和教練一起，我相信一定能奪下有價值的勝利。教練這次也會與我同行吧？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`FELICETTE_SPACESUIT_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};